sql:
SELECT asset_weight
FROM custom_basket_assets
WHERE basket_asset_id = 1;

SELECT COUNT(DISTINCT asset_class_id) AS positive_impact_count
FROM market_trends
WHERE trend_impact = 'Positive';

SELECT asset_class_name 
FROM asset_classes 
WHERE asset_class_id = 1;

SELECT asset_class_name, asset_class_risk_level
FROM asset_classes
ORDER BY asset_class_id;

SELECT transaction_id, amount
FROM investment_transactions
WHERE transaction_id = 0;

SELECT asset_class_id, SUM(total_investment_amount) AS total_investment
FROM asset_investments
GROUP BY asset_class_id;

SELECT news_title
FROM news_feed
WHERE news_id = 1;

SELECT COUNT(basket_id)
FROM custom_baskets
WHERE user_id = 0;

SELECT asset_class_id, investment_type_id, total_investment_amount
FROM asset_investments
WHERE investment_id = 1;

SELECT asset_class_id, investment_type_id, total_investment_amount
FROM asset_investments
WHERE investment_id = 1;

SELECT benchmark_value
FROM benchmark_data
WHERE benchmark_id = 0;

SELECT total_investment
FROM asset_performance
WHERE performance_id = 0;
